"""Ядро подготовки runtime приложения: каталоги, app.ini, логгер. Явно разделены boot ядра и модулей."""from __future__ import annotationsimport shutilfrom pathlib import Pathfrom typing import Callable, Mappingfrom src.core import AppConfigStorefrom src.core.app_locale import (    AVAILABLE_LANGUAGES,    first_available_language_code,    resolve_packaged_locale_path,    set_available_languages,    set_language,)from src.core.app_path import AppPathfrom src.core.filesystem import ensure_dirfrom src.core.logger import DEBUG, SystemLogger, SystemLoggerStoreclass CoreBootstrap:    """    Регистрация и выполнение обработчиков при boot приложения.    Порядок: core_boot(root) загружает app.ini в AppConfigStore; затем (после get())    lang_boot(paths, available_languages) — каталоги локалей и активный язык из [CORE].LANGUAGE;    далее add_module_boot(...) и modules_boot(paths).    """    _handlers: list[Callable[[AppPath], None]] = []    @staticmethod    def add_module_boot(fn: Callable[[AppPath], None]) -> None:        """Добавляет boot модуля: функцию, вызываемую при modules_boot. Сигнатура: fn(paths: AppPath) -> None."""        CoreBootstrap._handlers.append(fn)    @staticmethod    def core_boot(root: Path | None = None) -> AppPath:        """        Подготавливает runtime ядра: core-каталоги (projects, data, data/user, logs), app.ini, системный логгер.        Не создаёт доменные файлы модулей. Безопасна при повторном вызове.        Возвращает AppPath для передачи в modules_boot.        """        paths = AppPath.from_root(root)        ensure_dir(paths.projects_dir)        ensure_dir(paths.data_dir)        ensure_dir(paths.source_dir)        ensure_dir(paths.data_user_dir)        ensure_dir(paths.logs_dir)        ensure_dir(paths.cache_dir)        ensure_dir(paths.temp_dir)        ensure_dir(paths.root / "assets" / "locale")        SystemLoggerStore.set(            SystemLogger(logs_dir=paths.logs_dir, file_name="system", level=DEBUG)        )        AppConfigStore.load_or_create(paths.root)        SystemLoggerStore.set_level(AppConfigStore.get().core.log_level)        return paths    @staticmethod    def lang_boot(paths: AppPath, available_languages: Mapping[str, str] | None = None) -> None:        """        Регистрирует доступные языки, копирует locale JSON в runtime assets,        применяет сохранённый язык из AppConfigStore ([CORE] LANGUAGE), если код валиден;        иначе — первая доступная локаль (порядок как в переданном словаре).        """        if available_languages is None:            raise ValueError("available_languages must be provided")        set_available_languages(available_languages)        CoreBootstrap._sync_locale_assets(paths)        saved = (AppConfigStore.get().core.language or "").strip().lower().replace("-", "_")        if saved and saved in AVAILABLE_LANGUAGES:            set_language(saved)        else:            set_language(first_available_language_code())    @classmethod    def modules_boot(cls, paths: AppPath) -> None:        """Вызывает зарегистрированные обработчики модулей (add_module_boot). Вызывать после core_boot."""        for fn in cls._handlers:            fn(paths)    @staticmethod    def _sync_locale_assets(paths: AppPath) -> None:        """Копирует locale JSON в runtime assets для доступа после запуска."""        runtime_locale_dir = paths.root / "assets" / "locale"        ensure_dir(runtime_locale_dir)        for language in AVAILABLE_LANGUAGES:            source = resolve_packaged_locale_path(language, runtime_root=paths.root)            target = runtime_locale_dir / f"{language}.json"            if not source.is_file():                continue            if source.resolve() == target.resolve():                continue            shutil.copy2(source, target)core_boot = CoreBootstrap.core_bootlang_boot = CoreBootstrap.lang_boot__all__ = ["CoreBootstrap", "core_boot", "lang_boot"]